arguments.content:
$c = Get-Content 'C:\Users\73911\.openclaw\openclaw.json' -Raw | ConvertFrom-Json

Write-Host "=== 配置验证 ===" -ForegroundColor Cyan
Write-Host ""
Write-Host "[1] JSON语法: OK" -ForegroundColor Green
Write-Host ""

Write-Host "[2] Agent列表:" -ForegroundColor Yellow
foreach ($a in $c.agents.list) {
    Write-Host "  - $($a.id): $($a.name)"
}
Write-Host ""

Write-Host "[3] Bindings:" -ForegroundColor Yellow
foreach ($b in $c.bindings) {
    Write-Host "  - $($b.agentId) -> $($b.match.channel):$($b.match.accountId)"
}
Write-Host ""

Write-Host "[4] 飞书应用:" -ForegroundColor Yellow
foreach ($prop in $c.channels.feishu.accounts.PSObject.Properties) {
    if ($prop.Name -ne "default") {
        Write-Host "  - $($prop.Name): $($prop.Value.appId)"
    }
}
Write-Host ""

Write-Host "[5] Gateway: $($c.gateway.port)" -ForegroundColor Yellow

